const URL = 'https://practice-papers.onrender.com/question/getQuestionDetails/'

const getQuestionDetails = (questionID, setQuestionDetails, setLoading, setQuestion, setAllAnswer, setQuestionPoint, setQuestionType, setCorrectAnswer, setWrongAnswerFs, setWrongAnswerSe, setWrongAnswerTh) => {
    setLoading(true)
    fetch(`${URL}${questionID}`, {
        method: 'get',
        headers: { 'Content-Type': 'application/json' },
    })
        .then((response) => response.json())
        .then((responseJson) => {
            if (responseJson.message === 'success') {
                setQuestionDetails(responseJson.question)
                setQuestion(responseJson.question.question)
                setAllAnswer(responseJson.question.answer)
                setQuestionPoint(responseJson.question.questionPoints)
                setQuestionType(responseJson.question.typeOfAnswer)
                setCorrectAnswer(responseJson.question.correctAnswer)
                if (responseJson.question.typeOfAnswer == 'MCQ') {
                    const wrongAnswers = responseJson.question.wrongAnswer
                    for (let index = 0; index < wrongAnswers.length; index++) {
                        const element = wrongAnswers[index];
                        if (index == 0) {
                            setWrongAnswerFs(element)
                        } else if (index == 1) {
                            setWrongAnswerSe(element)
                        } else {
                            setWrongAnswerTh(element)
                        }
                    }
                }
                setLoading(false)
            } else {
                setLoading(false)
            }
        })
        .catch((error) => {
            console.log(error.message)
            setLoading(false)
        });
}

export default getQuestionDetails;
